// POST - Create redemption
app.post('/v1/redemptions', async (req, res) => {
  if (!dbClient) {
    return res.status(501).json({ error: 'Database not connected' });
  }
  
  try {
    const { tenant_id } = req.query;
    const { redemption_code, description, redemption_type, points_required, start_date, end_date, status, allowed_point_type_ids, quantity_available } = req.body;
    
    if (!tenant_id) {
      return res.status(400).json({ error: 'tenant_id required' });
    }
    
    // Validation
    if (!redemption_code) {
      return res.status(400).json({ error: 'redemption_code is required' });
    }
    if (!description) {
      return res.status(400).json({ error: 'description is required' });
    }
    if (!redemption_type || !['F', 'V'].includes(redemption_type)) {
      return res.status(400).json({ error: 'redemption_type must be F or V' });
    }
    if (redemption_type === 'F' && !points_required) {
      return res.status(400).json({ error: 'points_required is required for fixed redemptions' });
    }
    if (!status || !['A', 'I'].includes(status)) {
      return res.status(400).json({ error: 'status must be A or I' });
    }
    
    const query = `
      INSERT INTO redemption_rule (
        tenant_id,
        redemption_code,
        redemption_description,
        redemption_type,
        points_required,
        start_date,
        end_date,
        status,
        quantity_available
      )
      VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
      RETURNING *
    `;
    
    const result = await dbClient.query(query, [
      tenant_id,
      redemption_code,
      description,
      redemption_type,
      redemption_type === 'F' ? points_required : 0,
      start_date || null,
      end_date || null,
      status,
      quantity_available != null ? quantity_available : null
    ]);
    
    const redemption = result.rows[0];
    
    // Save allowed point types
    if (allowed_point_type_ids && allowed_point_type_ids.length > 0) {
      for (const pointTypeId of allowed_point_type_ids) {
        await dbClient.query(
          'INSERT INTO redemption_point_type (redemption_id, point_type_id) VALUES ($1, $2)',
          [redemption.redemption_id, pointTypeId]
        );
      }
    }
    
    res.status(201).json(redemption);
  } catch (error) {
    console.error('Error creating redemption:', error);
    if (error.code === '23505') { // Unique violation
      return res.status(400).json({ error: 'Redemption code already exists for this tenant' });
    }
    res.status(500).json({ error: error.message });
  }
});

// PUT - Update redemption
app.put('/v1/redemptions/:id', async (req, res) => {
  if (!dbClient) {
    return res.status(501).json({ error: 'Database not connected' });
  }
  
  try {
    const { id } = req.params;
    const { tenant_id } = req.query;
    const { redemption_code, description, redemption_type, points_required, start_date, end_date, status, allowed_point_type_ids, quantity_available } = req.body;
    
    if (!tenant_id) {
      return res.status(400).json({ error: 'tenant_id required' });
    }
    
    // Validation
    if (!redemption_code) {
      return res.status(400).json({ error: 'redemption_code is required' });
    }
    if (!description) {
      return res.status(400).json({ error: 'description is required' });
    }
    if (!redemption_type || !['F', 'V'].includes(redemption_type)) {
      return res.status(400).json({ error: 'redemption_type must be F or V' });
    }
    if (redemption_type === 'F' && !points_required) {
      return res.status(400).json({ error: 'points_required is required for fixed redemptions' });
    }
    if (!status || !['A', 'I'].includes(status)) {
      return res.status(400).json({ error: 'status must be A or I' });
    }
    
    const query = `
      UPDATE redemption_rule
      SET 
        redemption_code = $1,
        redemption_description = $2,
        redemption_type = $3,
        points_required = $4,
        start_date = $5,
        end_date = $6,
        status = $7,
        quantity_available = $8
      WHERE redemption_id = $9 AND tenant_id = $10
      RETURNING *
    `;
    
    const result = await dbClient.query(query, [
      redemption_code,
      description,
      redemption_type,
      redemption_type === 'F' ? points_required : 0,
      start_date || null,
      end_date || null,
      status,
      quantity_available != null ? quantity_available : null,
      id,
      tenant_id
    ]);
    
    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Redemption not found' });
    }
    
    // Update allowed point types - delete existing and re-insert
    await dbClient.query('DELETE FROM redemption_point_type WHERE redemption_id = $1', [id]);
    
    if (allowed_point_type_ids && allowed_point_type_ids.length > 0) {
      for (const pointTypeId of allowed_point_type_ids) {
        await dbClient.query(
          'INSERT INTO redemption_point_type (redemption_id, point_type_id) VALUES ($1, $2)',
          [id, pointTypeId]
        );
      }
    }
    
    res.json(result.rows[0]);
  } catch (error) {
    console.error('Error updating redemption:', error);
    if (error.code === '23505') { // Unique violation
      return res.status(400).json({ error: 'Redemption code already exists for this tenant' });
    }
    res.status(500).json({ error: error.message });
  }
});

