const BCRYPT_ROUNDS = 10;

// POST /v1/auth/login - Authenticate user
app.post('/v1/auth/login', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  
  const { username, password } = req.body;
  
  if (!username || !password) {
    return res.status(400).json({ error: 'Username and password required' });
  }
  
  try {
    const result = await dbClient.query(`
      SELECT u.user_id, u.username, u.password_hash, u.display_name, u.tenant_id, u.role, u.is_active,
             t.tenant_key, t.vertical_key
      FROM platform_user u
      LEFT JOIN tenant t ON t.tenant_id = u.tenant_id
      WHERE u.username = $1
    `, [username]);
    
    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'Invalid username or password' });
    }
    
    const user = result.rows[0];
    
    if (!user.is_active) {
      return res.status(401).json({ error: 'Account is deactivated' });
    }
    
    // Verify password
    const passwordMatch = await bcrypt.compare(password, user.password_hash);
    if (!passwordMatch) {
      return res.status(401).json({ error: 'Invalid username or password' });
    }
    
    // Update last_login
    await dbClient.query(
      'UPDATE platform_user SET last_login = NOW() WHERE user_id = $1',
      [user.user_id]
    );

    // Opportunistic session cleanup at login
    // Deletes SESSION_CLEANUP_COUNT expired sessions per login instead of background job
    try {
      await dbClient.query(
        `DELETE FROM session WHERE sid IN (
           SELECT sid FROM session WHERE expire < NOW() LIMIT $1
         )`,
        [SESSION_CLEANUP_COUNT]
      );
      debugLog(() => `Session cleanup: removed up to ${SESSION_CLEANUP_COUNT} expired sessions`);
    } catch (cleanupErr) {
      debugLog(() => `Session cleanup skipped: ${cleanupErr.message}`);
    }

    // Establish server-side session
    await new Promise((resolve, reject) => {
      req.session.regenerate((err) => {
        if (err) return reject(err);
        req.session.userId   = user.user_id;
        req.session.tenantId = user.tenant_id;
        req.session.role     = user.role;
        req.session.save((err2) => err2 ? reject(err2) : resolve());
      });
    });
    
    // Check ML service health (non-blocking, non-fatal)
    let ml_available = false;
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 3000);
      const mlResp = await fetch(`${ML_SERVICE_URL}/health`, { signal: controller.signal });
      clearTimeout(timeout);
      if (mlResp.ok) ml_available = true;
    } catch (e) { console.warn('ML health check failed:', e.message); }

    // Return user info (no password hash)
    res.json({
      user_id:      user.user_id,
      username:     user.username,
      display_name: user.display_name,
      tenant_id:    user.tenant_id,
      tenant_key:   user.tenant_key,
      vertical_key: user.vertical_key,
      role:         user.role,
      services:     { ml: ml_available }
    });

    // Log login (non-blocking)
    try {
      await dbClient.query(
        `INSERT INTO usage_log (user_id, tenant_id, action, ip_address, user_agent)
         VALUES ($1, $2, 'login', $3, $4)`,
        [user.user_id, user.tenant_id, req.ip, (req.headers['user-agent'] || '').substring(0, 500)]
      );
    } catch(e) { console.warn('Login usage_log error:', e.message); }

  } catch (error) {
    console.error('Error during login:', error);
    res.status(500).json({ error: error.message });
  }
});

// POST /v1/auth/logout - Destroy session
app.post('/v1/auth/logout', (req, res) => {
  const userId = req.session?.userId;
  const tenantId = req.session?.tenantId;
  req.session.destroy((err) => {
    if (err) {
      console.error('Logout error:', err);
      return res.status(500).json({ error: 'Logout failed' });
    }
    res.clearCookie('connect.sid');
    // Log logout (non-blocking)
    if (userId && dbClient) {
      dbClient.query(
        `INSERT INTO usage_log (user_id, tenant_id, action, ip_address) VALUES ($1, $2, 'logout', $3)`,
        [userId, tenantId, req.ip]
      ).catch(e => console.warn('Logout usage_log error:', e.message));
    }
    res.json({ success: true });
  });
});

