// GET /v1/audit/user-report - Get audit report for a user with date range
app.get('/v1/audit/user-report', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  
  const { user_id, tenant_id, start_date, end_date } = req.query;
  
  if (!user_id) {
    return res.status(400).json({ error: 'user_id is required' });
  }
  
  try {
    // First get user's link from user_id
    const userResult = await dbClient.query(
      'SELECT link FROM platform_user WHERE user_id = $1',
      [user_id]
    );
    
    if (userResult.rows.length === 0) {
      return res.status(404).json({ error: 'User not found' });
    }
    
    const userLink = userResult.rows[0].link;
    
    // Build WHERE clauses using compressed timestamp
    let dateFilter = '';
    const params = [userLink];
    let paramIndex = 2;
    
    if (start_date && end_date) {
      dateFilter = `AND a.audit_ts >= timestamp_to_audit_ts($${paramIndex}::date::timestamp) AND a.audit_ts <= timestamp_to_audit_ts(($${paramIndex + 1}::date + 1)::timestamp)`;
      params.push(start_date, end_date);
      paramIndex += 2;
    } else if (start_date) {
      dateFilter = `AND a.audit_ts >= timestamp_to_audit_ts($${paramIndex}::date::timestamp)`;
      params.push(start_date);
      paramIndex++;
    } else if (end_date) {
      dateFilter = `AND a.audit_ts <= timestamp_to_audit_ts(($${paramIndex}::date + 1)::timestamp)`;
      params.push(end_date);
      paramIndex++;
    }
    
    // Query all audit tables and union results
    const queries = ['1', '2', '3', '4', '5'].map(size => `
      SELECT 
        a.link,
        a.p_link,
        a.user_link,
        audit_ts_to_timestamp(a.audit_ts) as action_time,
        a.audit_ts,
        a.entity_key::text as entity_key,
        a.action,
        '${size}' as key_size
      FROM audit_log_${size} a
      WHERE a.user_link = $1 ${dateFilter}
    `);
    
    const unionQuery = queries.join(' UNION ALL ') + ' ORDER BY audit_ts DESC LIMIT 1000';
    
    const result = await dbClient.query(unionQuery, params);
    
    // Hydrate each row with entity details
    const hydratedRows = await Promise.all(result.rows.map(async (row) => {
      // Get entity table name from p_link
      row.entity_type = await getEntityTableName(row.p_link);
      
      // For activity entities (soft delete means data still exists)
      if (row.entity_type === 'activity') {
        try {
          const summary = await renderActivitySummary(row.entity_key, tenant_id || 1);
          if (summary) {
            row.activity_summary = summary;
          }
        } catch (e) {
          console.warn('Audit log lookup error:', e.message);
        }
      }
      
      // For member entities that still exist
      if (row.entity_type === 'member' && row.action !== 'D') {
        try {
          const memberResult = await dbClient.query(`
            SELECT membership_number, fname, lname 
            FROM member WHERE link = $1
          `, [row.entity_key]);
          if (memberResult.rows.length > 0) {
            const m = memberResult.rows[0];
            row.member_summary = {
              membership_number: m.membership_number,
              member_name: `${m.fname} ${m.lname}`
            };
          }
        } catch (e) {
          console.warn('Audit log lookup error:', e.message);
        }
      }
      
      // For edits, get the field changes from audit_change
      if (row.action === 'E') {
        try {
          const changesResult = await dbClient.query(`
            SELECT af.table_name, af.field_name, ac.old_value, ac.new_value
            FROM audit_change ac
            JOIN audit_field af ON af.link = ac.field_link
            WHERE ac.p_link = $1 AND ac.key_size = $2
            ORDER BY af.field_name
          `, [row.link, row.key_size]);
          
          if (changesResult.rows.length > 0) {
            row.field_changes = changesResult.rows;
          }
        } catch (e) {
          console.warn('Audit log lookup error:', e.message);
        }
      }
      
      return row;
    }));
    
    res.json(hydratedRows);
    
  } catch (error) {
    console.error('Error fetching user audit report:', error);
    res.status(500).json({ error: error.message });
  }
});

// ============================================================
// REGISTRY AUDIT HISTORY ENDPOINT
// GET /v1/stability-registry/audit-history
//   ?user_id=N    — filter by user (By User view)
//   ?program_id=N — filter by clinic (By Clinic view)
//   (neither)     — global view
// ============================================================
app.get('/v1/stability-registry/audit-history', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const tenantId = req.tenantId;
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  const { user_id, program_id, start_date, end_date } = req.query;

  try {
    // Get the entity type link for stability_registry (auto-creates if first time)
    const { link: entityTypeLink, key_size } = await getOrCreateEntityLink(tenantId, 'stability_registry');
    const auditTable = `audit_log_${key_size}`;

    // Build filters
    let dateFilter = '';
    const params = [entityTypeLink];
    let paramIndex = 2;

    if (start_date) {
      dateFilter += ` AND a.audit_ts >= timestamp_to_audit_ts($${paramIndex}::date::timestamp)`;
      params.push(start_date);
      paramIndex++;
    }
    if (end_date) {
      dateFilter += ` AND a.audit_ts <= timestamp_to_audit_ts(($${paramIndex}::date + 1)::timestamp)`;
      params.push(end_date);
      paramIndex++;
    }

    let userFilter = '';
    if (user_id) {
      const userResult = await dbClient.query('SELECT link FROM platform_user WHERE user_id = $1', [user_id]);
      if (userResult.rows.length > 0) {
        userFilter = ` AND a.user_link = $${paramIndex}`;
        params.push(userResult.rows[0].link);
        paramIndex++;
      }
    }

    // Query audit entries for stability_registry, join to registry + member for context
    const result = await dbClient.query(`
      SELECT
        a.link as audit_link,
        a.entity_key as registry_link,
        audit_ts_to_timestamp(a.audit_ts) as action_time,
        a.audit_ts,
        a.action,
        a.user_link,
        u.display_name as user_name,
        sr.member_link,
        sr.urgency,
        sr.source_stream,
        sr.reason_code,
        sr.reason_text,
        sr.status as current_status,
        sr.resolution_code,
        sr.resolution_notes,
        m.fname,
        m.lname,
        m.membership_number
      FROM ${auditTable} a
      LEFT JOIN platform_user u ON a.user_link = u.link
      LEFT JOIN stability_registry sr ON a.entity_key = sr.link
      LEFT JOIN member m ON sr.member_link = m.link
      WHERE a.p_link = $1 ${dateFilter} ${userFilter}
      ORDER BY a.audit_ts DESC
      LIMIT 500
    `, params);

    let rows = result.rows;

    // Clinic filter: only include entries for members in the specified program
    if (program_id) {
      const ppInfo = await getMoleculeStorageInfo(tenantId, 'PARTNER_PROGRAM');
      if (ppInfo) {
        const col2 = ppInfo.columns[1];
        const encoded = encodeValue(parseInt(program_id), col2.size, col2.valueType);
        const clinicMembers = await dbClient.query(
          `SELECT p_link FROM ${ppInfo.tableName} WHERE molecule_id = ${ppInfo.moleculeId} AND attaches_to = 'M' AND ${col2.name} = $1`,
          [encoded]
        );
        const memberSet = new Set(clinicMembers.rows.map(r => r.p_link));
        rows = rows.filter(r => memberSet.has(r.member_link));
      }
    }

    // For edit actions, get field-level changes
    for (const row of rows) {
      if (row.action === 'E') {
        try {
          const changesResult = await dbClient.query(`
            SELECT af.field_name, ac.old_value, ac.new_value
            FROM audit_change ac
            JOIN audit_field af ON ac.field_link = af.link
            WHERE ac.p_link = $1 AND ac.key_size = $2
          `, [row.audit_link, key_size]);
          row.changes = changesResult.rows;
        } catch (e) {
          row.changes = [];
        }
      }
    }

    // Build action descriptions for the UI
    rows = rows.map(r => {
      let description = '';
      if (r.action === 'A') {
        description = `Created ${r.urgency} registry item: ${r.reason_text || r.reason_code}`;
      } else if (r.action === 'E') {
        const statusChange = (r.changes || []).find(c => c.field_name === 'status');
        if (statusChange) {
          const labels = { O: 'Open', A: 'Assigned', R: 'Resolved' };
          description = `${labels[statusChange.old_value] || statusChange.old_value} → ${labels[statusChange.new_value] || statusChange.new_value}`;
          if (statusChange.new_value === 'R' && r.resolution_notes) {
            description += `: ${r.resolution_notes}`;
          }
        } else {
          description = 'Updated registry item';
        }
      }
      return {
        ...r,
        action_description: description,
        physician_name: r.fname && r.lname ? `${r.fname} ${r.lname}` : 'Unknown'
      };
    });

    res.json({ items: rows, total: rows.length });

  } catch (error) {
    console.error('Error fetching registry audit history:', error);
    res.status(500).json({ error: error.message });
  }
});

