// PUT /v1/member-surveys/:link/answers — save answers (partial) or submit (complete)
// On submit: if survey has score_function, scores and creates accrual activity
// Optional body param: activity_date (YYYY-MM-DD) to backdate completion timestamp
app.put('/v1/member-surveys/:link/answers', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const msLink = parseInt(req.params.link);
  const { answers, submit, activity_date, pulse_respondent_link, comment } = req.body;
  const tenantId = req.tenantId;
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });
  const client = await dbClient.connect();
  try {
    // Fetch member_survey with survey details (need score_function, member_link)
    const msResult = await client.query(`
      SELECT ms.link, ms.end_ts, ms.member_link, ms.survey_link,
             s.score_function, s.survey_code, s.survey_name, s.note_alert
      FROM member_survey ms
      JOIN survey s ON s.link = ms.survey_link AND s.tenant_id = $2
      WHERE ms.link = $1
    `, [msLink, tenantId]);
    if (!msResult.rows.length) { client.release(); return res.status(404).json({ error: 'Not found' }); }
    if (msResult.rows[0].end_ts) { client.release(); return res.status(400).json({ error: 'Survey already completed' }); }
    const msRow = msResult.rows[0];

    await client.query('BEGIN');

    // Save answers
    await client.query(`DELETE FROM member_survey_answer WHERE member_survey_link=$1`, [msLink]);

    if (answers && answers.length) {
      for (const a of answers) {
        const aLink = await getNextLink(tenantId, 'member_survey_answer');
        await client.query(`
          INSERT INTO member_survey_answer (link, member_survey_link, question_link, answer)
          VALUES ($1,$2,$3,$4)
        `, [aLink, msLink, a.question_link, a.answer]);
      }
    }

    let scoringResult = null;
    let accrualResult = null;

    if (submit) {
      // Use provided activity_date for backdating (seeding/backfill), otherwise now
      let endTs;
      let accrualDate;
      if (activity_date && /^\d{4}-\d{2}-\d{2}$/.test(activity_date)) {
        endTs = Math.floor(new Date(activity_date + 'T12:00:00').getTime() / 1000);
        accrualDate = activity_date;
      } else {
        endTs = Math.floor(Date.now() / 1000);
        accrualDate = todayLocal();
      }
      await client.query(`UPDATE member_survey SET end_ts=$1 WHERE link=$2`, [endTs, msLink]);

      // --- Score function wiring ---
      if (msRow.score_function) {
        debugLog(() => `\n📊 Survey submitted — scoring via ${msRow.score_function}`);

        // Enrich answers with category info for the scoring function
        const enrichedAnswers = await client.query(`
          SELECT msa.question_link, msa.answer,
                 sqc.category_code, sqc.category_name
          FROM member_survey_answer msa
          JOIN survey_question sq ON sq.link = msa.question_link
          JOIN survey_question_category sqc ON sqc.link = sq.category_link
          WHERE msa.member_survey_link = $1
        `, [msLink]);

        const surveyData = {
          member_link: msRow.member_link,
          member_survey_link: msLink,
          survey_link: msRow.survey_link,
          answers: enrichedAnswers.rows,
          tenant_id: tenantId
        };

        scoringResult = await callScoringFunction(msRow.score_function, surveyData, { db: client, tenantId });
        debugLog(() => `   Scoring result: ${JSON.stringify(scoringResult)}`);

        if (scoringResult.success && scoringResult.points !== undefined) {
          // Create accrual activity via existing createAccrualActivity
          const activityData = {
            activity_date: accrualDate,
            base_points: scoringResult.points,
            ACCRUAL_TYPE: scoringResult.accrual_type || 'SURVEY',
            MEMBER_SURVEY_LINK: msLink,
            SURVEY_LINK: msRow.survey_code
          };
          if (pulse_respondent_link) activityData.PULSE_RESPONDENT_LINK = pulse_respondent_link;
          if (comment && comment.trim()) activityData.ACTIVITY_COMMENT = comment.trim();

          // Pass through signals from scoring function (e.g., PULSE_Q3, STABILITY_IMMEDIATE)
          if (scoringResult.signals && scoringResult.signals.length > 0) {
            activityData.SIGNAL = scoringResult.signals[0];
            debugLog(() => `   🚨 Signal from scoring: ${scoringResult.signals.join(', ')}`);
          }

          debugLog(() => `   Creating accrual: ${JSON.stringify(activityData)}`);
          accrualResult = await createAccrualActivity(msRow.member_link, activityData, tenantId);
          debugLog(() => `   ✅ Accrual created: link=${accrualResult.link}, points=${scoringResult.points}`);
        } else if (!scoringResult.success) {
          debugLog(() => `   ⚠️ Scoring failed: ${scoringResult.error} — survey saved but no accrual created`);
        }
      }
    }

    await client.query('COMMIT');

    // Custauth POST_ACCRUAL hook — composite recalc after survey scoring
    if (accrualResult) {
      try {
        const postCustauth = await getCustauth(tenantId);
        await postCustauth('POST_ACCRUAL', { ACCRUAL_TYPE: scoringResult.accrual_type || 'SURVEY', base_points: scoringResult.points }, { tenantId, memberLink: msRow.member_link, db: dbClient, accrualResult });
      } catch (postErr) {
        console.error('POST_ACCRUAL custauth error (non-fatal):', postErr.message);
      }
    }

    // Clear FULL_PPSI_REQUESTED flag after full PPSI completion (34 questions)
    if (submit && accrualResult && msRow.survey_link === 1 && answers.length >= 34) {
      try {
        await deleteMoleculeRow(msRow.member_link, 'FULL_PPSI_REQUESTED', {}, tenantId);
      } catch (e) { console.warn('Clear FULL_PPSI_REQUESTED error (non-fatal):', e.message); }
    }

    // PPSI Safety Alert — fire notification when note_alert survey has a comment
    if (submit && comment && comment.trim() && msRow.note_alert) {
      try {
        // Get member name for notification context
        const memberRec = await dbClient.query(
          `SELECT fname, lname, membership_number FROM member WHERE link = $1`, [msRow.member_link]
        );
        const memberName = memberRec.rows.length ? `${memberRec.rows[0].fname} ${memberRec.rows[0].lname}` : 'Unknown';
        const membershipNumber = memberRec.rows.length ? memberRec.rows[0].membership_number : '';

        // Create note review record for staff to action
        if (accrualResult) {
          try {
            await dbClient.query(
              `INSERT INTO survey_note_review (activity_link, member_link, tenant_id, review_status)
               VALUES ($1, $2, $3, 'pending')`,
              [accrualResult.link, msRow.member_link, tenantId]
            );
          } catch (reviewErr) {
            console.error('survey_note_review insert error (non-fatal):', reviewErr.message);
          }
        }

        await fireNotificationEvent('PPSI_NOTE_ENTERED', tenantId, {
          memberLink: msRow.member_link,
          memberName: memberName,
          detail: comment.trim().length > 150 ? comment.trim().substring(0, 147) + '...' : comment.trim(),
          sourcePage: 'physician_detail.html',
          sourceLink: membershipNumber
        });
        debugLog(() => `   🔔 PPSI note alert fired for ${memberName}`);
      } catch (notifyErr) {
        console.error('PPSI note alert notification error (non-fatal):', notifyErr.message);
      }
    }

    const response = {
      member_survey_link: msLink,
      saved: answers ? answers.length : 0,
      submitted: !!submit
    };
    if (scoringResult) response.scoring = scoringResult;
    if (accrualResult) response.accrual = { link: accrualResult.link, points: scoringResult.points };

    res.json(response);
  } catch (error) {
    await client.query('ROLLBACK');
    console.error('Error saving survey answers:', error);
    res.status(500).json({ error: error.message });
  } finally {
    client.release();
  }
});

