// ============================================================
// SCHEDULED JOBS — Core Platform
// ============================================================

// In-memory registry of job handler functions keyed by job_code
const scheduledJobHandlers = {};

/**
 * Register a scheduled job handler function.
 * Call this at module level to wire a job_code to its implementation.
 * The handler receives (tenantId, scheduledJobId, dbClient) and must return
 * { analyzed, processed, flagged }.
 */
function registerJobHandler(jobCode, handlerFn) {
  scheduledJobHandlers[jobCode] = handlerFn;
}

/**
 * Run a single scheduled job: call its handler, log results.
 * @param {number} scheduledJobId - PK of scheduled_job row
 * @param {string} runSource - 'startup', 'daily', 'manual', 'member-update'
 */
async function runScheduledJob(scheduledJobId, runSource = 'daily') {
  if (!dbClient) return;

  try {
    const jobResult = await dbClient.query(
      'SELECT * FROM scheduled_job WHERE scheduled_job_id = $1 AND is_active = TRUE',
      [scheduledJobId]
    );
    if (!jobResult.rows.length) return null;
    const job = jobResult.rows[0];

    const handler = scheduledJobHandlers[job.job_code];
    if (!handler) {
      console.error(`Scheduled jobs: no handler registered for job_code '${job.job_code}'`);
      return null;
    }

    // Create log entry
    const logResult = await dbClient.query(
      `INSERT INTO scheduled_job_log (scheduled_job_id, tenant_id, run_source) VALUES ($1, $2, $3) RETURNING log_id`,
      [scheduledJobId, job.tenant_id, runSource]
    );
    const logId = logResult.rows[0].log_id;

    try {
      const result = await handler(job.tenant_id, scheduledJobId, dbClient);
      const analyzed = result?.analyzed || 0;
      const processed = result?.processed || 0;
      const flagged = result?.flagged || 0;

      await dbClient.query(
        `UPDATE scheduled_job_log SET finished_at = NOW(), records_analyzed = $1, records_processed = $2, items_flagged = $3, status = 'completed' WHERE log_id = $4`,
        [analyzed, processed, flagged, logId]
      );

      await dbClient.query(
        `UPDATE scheduled_job SET last_run_at = NOW(), next_run_at = NOW() + (interval_minutes || ' minutes')::interval WHERE scheduled_job_id = $1`,
        [scheduledJobId]
      );

      debugLog(() => `Scheduled job '${job.job_code}' (tenant ${job.tenant_id}): analyzed=${analyzed}, processed=${processed}, flagged=${flagged}`);
      return { logId, analyzed, processed, flagged, status: 'completed' };

    } catch (handlerErr) {
      await dbClient.query(
        `UPDATE scheduled_job_log SET finished_at = NOW(), status = 'error', error_message = $1 WHERE log_id = $2`,
        [handlerErr.message, logId]
      );
      console.error(`Scheduled job '${job.job_code}' error:`, handlerErr.message);
      return { logId, status: 'error', error: handlerErr.message };
    }

  } catch (e) {
    console.error('Scheduled jobs error:', e.message);
    return null;
  }
}

/**
 * Run all due scheduled jobs across all tenants.
 * Called on server startup, by scheduler, and by "run now".
 */
async function runDueScheduledJobs(runSource = 'daily') {
  if (!dbClient) return [];
  const results = [];

  try {
    const dueJobs = await dbClient.query(
      `SELECT scheduled_job_id FROM scheduled_job WHERE is_active = TRUE AND (next_run_at IS NULL OR next_run_at <= NOW()) ORDER BY tenant_id, scheduled_job_id`
    );

    for (const row of dueJobs.rows) {
      const result = await runScheduledJob(row.scheduled_job_id, runSource);
      if (result) results.push(result);
    }
  } catch (e) {
    console.error('runDueScheduledJobs error:', e.message);
  }

  return results;
}

// Scheduler — checks every minute for due jobs
let jobSchedulerInterval = null;
function startJobScheduler() {
  if (jobSchedulerInterval) return;
  jobSchedulerInterval = setInterval(async () => {
    try {
      const dueJobs = await dbClient.query(
        `SELECT scheduled_job_id FROM scheduled_job WHERE is_active = TRUE AND next_run_at <= NOW()`
      );
      for (const row of dueJobs.rows) {
        await runScheduledJob(row.scheduled_job_id, 'daily');
      }
    } catch (e) {
      logPlatformError('error', 'JobScheduler', 'Scheduled job check failed', { error: e.message });
    }
  }, 60000); // Check every 60 seconds
}

// --- Scheduled Jobs API Endpoints ---

// GET /v1/scheduled/jobs — list all jobs for a tenant
app.get('/v1/scheduled/jobs', async (req, res) => {
  const tenantId = parseInt(req.query.tenant_id);
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const result = await dbClient.query(
      `SELECT sj.*,
              (SELECT count(*) FROM scheduled_job_log sjl WHERE sjl.scheduled_job_id = sj.scheduled_job_id) as total_runs,
              (SELECT started_at FROM scheduled_job_log sjl WHERE sjl.scheduled_job_id = sj.scheduled_job_id ORDER BY started_at DESC LIMIT 1) as last_run_started
       FROM scheduled_job sj WHERE sj.tenant_id = $1 ORDER BY sj.job_name`,
      [tenantId]
    );
    res.json(result.rows);
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// POST /v1/scheduled/jobs/:id/run — run now
app.post('/v1/scheduled/jobs/:id/run', async (req, res) => {
  const jobId = parseInt(req.params.id);
  try {
    const result = await runScheduledJob(jobId, 'manual');
    if (!result) return res.status(404).json({ error: 'Job not found or inactive' });
    res.json(result);
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// PUT /v1/scheduled/jobs/:id — update job (toggle active, change interval)
app.put('/v1/scheduled/jobs/:id', async (req, res) => {
  const jobId = parseInt(req.params.id);
  const { is_active, interval_minutes, preferred_start_time } = req.body;

  try {
    const sets = [];
    const vals = [];
    let idx = 1;

    if (is_active !== undefined) { sets.push(`is_active = $${idx++}`); vals.push(is_active); }
    if (interval_minutes !== undefined) { sets.push(`interval_minutes = $${idx++}`); vals.push(interval_minutes); }
    if (preferred_start_time !== undefined) { sets.push(`preferred_start_time = $${idx++}`); vals.push(preferred_start_time); }

    if (!sets.length) return res.status(400).json({ error: 'Nothing to update' });

    vals.push(jobId);
    await dbClient.query(`UPDATE scheduled_job SET ${sets.join(', ')} WHERE scheduled_job_id = $${idx}`, vals);
    res.json({ success: true });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// GET /v1/scheduled/jobs/:id/logs — run history for a job
app.get('/v1/scheduled/jobs/:id/logs', async (req, res) => {
  const jobId = parseInt(req.params.id);
  const limit = parseInt(req.query.limit) || 20;

  try {
    const result = await dbClient.query(
      `SELECT * FROM scheduled_job_log WHERE scheduled_job_id = $1 ORDER BY started_at DESC LIMIT $2`,
      [jobId, limit]
    );
    res.json(result.rows);
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// POST /v1/scheduled/run-all — run all due jobs now (manual trigger)
app.post('/v1/scheduled/run-all', async (req, res) => {
  try {
    const results = await runDueScheduledJobs('manual');
    res.json({ jobs_run: results.length, results });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// ============================================================
// MEDS — Missing Event Detection System
// ============================================================

/**
 * Calculate the next MEDS due date for a member.
 * Scans all surveys and compliance items, finds the earliest next-due date,
 * writes it to member.meds_next_due. Called after processing or event completion.
 *
 * If the computed date is today or past, automatically calls processMedsForMember.
 *
 * @param {string} memberLink - 5-byte member PK
 * @param {number} tenantId
 * @param {object} client - DB client (must be in a transaction if caller wants atomicity)
 */
async function calculateMedsNextDue(memberLink, tenantId, client) {
  const db = client || dbClient;
  if (!db) return;

  const SENTINEL_2137 = (() => {
    const epoch = new Date(1959, 11, 3);
    const target = new Date(2137, 0, 1);
    return Math.floor((target - epoch) / (1000 * 60 * 60 * 24)) - 32768;
  })();

  const todayBillEpoch = dateToMoleculeInt(new Date());

  let earliestDue = SENTINEL_2137;

  try {
    // --- Survey cadences ---
    // Find all active surveys for this tenant with a cadence
    const surveys = await db.query(
      `SELECT s.link AS survey_link, s.cadence_days
       FROM survey s
       WHERE s.tenant_id = $1 AND s.status = 'A' AND s.cadence_days IS NOT NULL AND s.cadence_days > 0`,
      [tenantId]
    );

    for (const survey of surveys.rows) {
      // Find most recent completed survey for this member
      const lastSurvey = await db.query(
        `SELECT end_ts FROM member_survey
         WHERE member_link = $1 AND survey_link = $2 AND end_ts IS NOT NULL
         ORDER BY end_ts DESC LIMIT 1`,
        [memberLink, survey.survey_link]
      );

      let nextDue;
      if (!lastSurvey.rows.length) {
        // Never taken — due now
        nextDue = todayBillEpoch;
      } else {
        // Convert Unix timestamp to Bill epoch date, add cadence days
        const lastDate = new Date(lastSurvey.rows[0].end_ts * 1000);
        const lastBillEpoch = dateToMoleculeInt(lastDate);
        nextDue = lastBillEpoch + survey.cadence_days;
      }

      if (nextDue < earliestDue) earliestDue = nextDue;
    }

    // --- Compliance item cadences ---
    const compItems = await db.query(
      `SELECT mc.member_compliance_id, mc.cadence_days
       FROM member_compliance mc
       WHERE mc.member_link = $1 AND mc.tenant_id = $2 AND mc.status = 'active' AND mc.cadence_days IS NOT NULL AND mc.cadence_days > 0`,
      [memberLink, tenantId]
    );

    for (const ci of compItems.rows) {
      const lastResult = await db.query(
        `SELECT result_date FROM compliance_result
         WHERE member_compliance_id = $1
         ORDER BY result_date DESC LIMIT 1`,
        [ci.member_compliance_id]
      );

      let nextDue;
      if (!lastResult.rows.length) {
        // Never completed — due now
        nextDue = todayBillEpoch;
      } else {
        nextDue = lastResult.rows[0].result_date + ci.cadence_days;
      }

      if (nextDue < earliestDue) earliestDue = nextDue;
    }

    // Write the date
    await db.query(
      `UPDATE member SET meds_next_due = $1 WHERE link = $2`,
      [earliestDue, memberLink]
    );

    // If due today or past, process immediately
    if (earliestDue <= todayBillEpoch) {
      await processMedsForMember(memberLink, tenantId, client);
    }

  } catch (e) {
    console.error(`calculateMedsNextDue error for member ${memberLink}:`, e.message);
  }
}

/**
 * Process all overdue MEDS items for a single member.
 * Locks the member record, checks each survey and compliance item against cadence,
 * fires notifications for overdue items, creates registry items for consecutive misses.
 * When done, calls calculateMedsNextDue to set next date.
 *
 * @param {string} memberLink - 5-byte member PK
 * @param {number} tenantId
 * @param {object} [externalClient] - if provided, caller owns the transaction
 */
async function processMedsForMember(memberLink, tenantId, externalClient) {
  if (!dbClient) return { analyzed: 0, processed: 0, flagged: 0 };

  const pool = dbClient;  // Use the pool for a dedicated client
  let client;
  let ownsTransaction = false;

  if (externalClient) {
    client = externalClient;
  } else {
    client = await pool.connect ? await pool.connect() : pool;
    ownsTransaction = true;
  }

  const todayBillEpoch = dateToMoleculeInt(new Date());
  let analyzed = 0;
  let processed = 0;
  let flagged = 0;
  const results = [];

  try {
    if (ownsTransaction) await client.query('BEGIN');

    // Lock member record
    await client.query('SELECT link FROM member WHERE link = $1 FOR UPDATE', [memberLink]);

    // Get member name for notifications
    const memberResult = await client.query(
      'SELECT fname, lname, membership_number FROM member WHERE link = $1',
      [memberLink]
    );
    const member = memberResult.rows[0];
    const memberName = member ? `${member.fname || ''} ${member.lname || ''}`.trim() : 'Unknown';

    // --- Check surveys ---
    const surveys = await client.query(
      `SELECT s.link AS survey_link, s.survey_code, s.survey_name, s.cadence_days
       FROM survey s
       WHERE s.tenant_id = $1 AND s.status = 'A' AND s.cadence_days IS NOT NULL AND s.cadence_days > 0`,
      [tenantId]
    );

    for (const survey of surveys.rows) {
      analyzed++;

      const lastSurvey = await client.query(
        `SELECT end_ts FROM member_survey
         WHERE member_link = $1 AND survey_link = $2 AND end_ts IS NOT NULL
         ORDER BY end_ts DESC LIMIT 1`,
        [memberLink, survey.survey_link]
      );

      let nextDue;
      if (!lastSurvey.rows.length) {
        nextDue = todayBillEpoch; // Never taken
      } else {
        const lastDate = new Date(lastSurvey.rows[0].end_ts * 1000);
        const lastBillEpoch = dateToMoleculeInt(lastDate);
        nextDue = lastBillEpoch + survey.cadence_days;
      }

      if (nextDue > todayBillEpoch) continue; // Not due yet

      processed++;
      const daysOverdue = todayBillEpoch - nextDue;

      // Count consecutive misses (how many cadence periods overdue)
      const consecutiveMisses = Math.floor(daysOverdue / survey.cadence_days) + 1;

      // Fire notification
      await fireNotificationEvent('MEDS_SURVEY_OVERDUE', tenantId, {
        memberLink,
        memberName,
        detail: `${survey.survey_name} overdue by ${daysOverdue} day(s) (${consecutiveMisses} consecutive miss${consecutiveMisses > 1 ? 'es' : ''})`,
        sourcePage: 'meds'
      }, client);
      flagged++;
      results.push({ type: 'survey', code: survey.survey_code, name: survey.survey_name, days_overdue: daysOverdue, consecutive_misses: consecutiveMisses });

      // If 3+ consecutive misses, create a registry item
      if (consecutiveMisses >= 3) {
        await fireNotificationEvent('MEDS_CONSECUTIVE_MISS', tenantId, {
          memberLink,
          memberName,
          detail: `${survey.survey_name}: ${consecutiveMisses} consecutive missed assessments`,
          sourcePage: 'meds'
        }, client);
      }
    }

    // --- Check compliance items ---
    const compItems = await client.query(
      `SELECT mc.member_compliance_id, mc.cadence_days, ci.item_code, ci.item_name
       FROM member_compliance mc
       JOIN compliance_item ci ON mc.compliance_item_id = ci.compliance_item_id
       WHERE mc.member_link = $1 AND mc.tenant_id = $2 AND mc.status = 'active' AND mc.cadence_days IS NOT NULL AND mc.cadence_days > 0`,
      [memberLink, tenantId]
    );

    for (const ci of compItems.rows) {
      analyzed++;

      const lastResult = await client.query(
        `SELECT result_date FROM compliance_result
         WHERE member_compliance_id = $1
         ORDER BY result_date DESC LIMIT 1`,
        [ci.member_compliance_id]
      );

      let nextDue;
      if (!lastResult.rows.length) {
        nextDue = todayBillEpoch; // Never completed
      } else {
        nextDue = lastResult.rows[0].result_date + ci.cadence_days;
      }

      if (nextDue > todayBillEpoch) continue; // Not due yet

      processed++;
      const daysOverdue = todayBillEpoch - nextDue;
      const consecutiveMisses = Math.floor(daysOverdue / ci.cadence_days) + 1;

      await fireNotificationEvent('MEDS_COMPLIANCE_OVERDUE', tenantId, {
        memberLink,
        memberName,
        detail: `${ci.item_name} overdue by ${daysOverdue} day(s) (${consecutiveMisses} consecutive miss${consecutiveMisses > 1 ? 'es' : ''})`,
        sourcePage: 'meds'
      }, client);
      flagged++;
      results.push({ type: 'compliance', code: ci.item_code, name: ci.item_name, days_overdue: daysOverdue, consecutive_misses: consecutiveMisses });

      if (consecutiveMisses >= 3) {
        await fireNotificationEvent('MEDS_CONSECUTIVE_MISS', tenantId, {
          memberLink,
          memberName,
          detail: `${ci.item_name}: ${consecutiveMisses} consecutive missed events`,
          sourcePage: 'meds'
        }, client);
      }
    }

    // Recalculate next due date (but don't recurse — skip the auto-process check)
    // We just processed, so update the date directly
    let earliestDue = (() => {
      const epoch = new Date(1959, 11, 3);
      const target = new Date(2137, 0, 1);
      return Math.floor((target - epoch) / (1000 * 60 * 60 * 24)) - 32768;
    })();

    // Recalc from surveys
    for (const survey of surveys.rows) {
      const lastSurvey = await client.query(
        `SELECT end_ts FROM member_survey
         WHERE member_link = $1 AND survey_link = $2 AND end_ts IS NOT NULL
         ORDER BY end_ts DESC LIMIT 1`,
        [memberLink, survey.survey_link]
      );
      let nextDue;
      if (!lastSurvey.rows.length) {
        nextDue = todayBillEpoch + survey.cadence_days; // Just flagged, next check is one cadence from now
      } else {
        const lastDate = new Date(lastSurvey.rows[0].end_ts * 1000);
        nextDue = dateToMoleculeInt(lastDate) + survey.cadence_days;
        // If still overdue, next check is tomorrow (don't re-flag same day)
        if (nextDue <= todayBillEpoch) nextDue = todayBillEpoch + 1;
      }
      if (nextDue < earliestDue) earliestDue = nextDue;
    }

    // Recalc from compliance
    for (const ci of compItems.rows) {
      const lastResult = await client.query(
        `SELECT result_date FROM compliance_result
         WHERE member_compliance_id = $1
         ORDER BY result_date DESC LIMIT 1`,
        [ci.member_compliance_id]
      );
      let nextDue;
      if (!lastResult.rows.length) {
        nextDue = todayBillEpoch + ci.cadence_days;
      } else {
        nextDue = lastResult.rows[0].result_date + ci.cadence_days;
        if (nextDue <= todayBillEpoch) nextDue = todayBillEpoch + 1;
      }
      if (nextDue < earliestDue) earliestDue = nextDue;
    }

    await client.query('UPDATE member SET meds_next_due = $1 WHERE link = $2', [earliestDue, memberLink]);

    if (ownsTransaction) await client.query('COMMIT');

  } catch (e) {
    if (ownsTransaction) await client.query('ROLLBACK');
    console.error(`processMedsForMember error for ${memberLink}:`, e.message);
  } finally {
    if (ownsTransaction && client.release) client.release();
  }

  return { analyzed, processed, flagged, results };
}

// --- MEDS Scheduled Job Handler ---
registerJobHandler('MEDS', async (tenantId, scheduledJobId, db) => {
  const todayBillEpoch = dateToMoleculeInt(new Date());

  // Find all members with meds_next_due <= today
  const dueMembers = await db.query(
    `SELECT link FROM member WHERE tenant_id = $1 AND meds_next_due <= $2 AND is_active = TRUE`,
    [tenantId, todayBillEpoch]
  );

  // FILTER_MEMBER_LIST custauth hook
  const custauth = await getCustauth(tenantId);
  const filteredMembers = await custauth('FILTER_MEMBER_LIST', dueMembers.rows, { tenantId, db });

  let totalAnalyzed = 0;
  let totalProcessed = 0;
  let totalFlagged = 0;

  for (const row of filteredMembers) {
    const result = await processMedsForMember(row.link, tenantId);
    totalAnalyzed += result.analyzed;
    totalProcessed += result.processed;
    totalFlagged += result.flagged;
  }

  return { analyzed: dueMembers.rows.length, processed: totalProcessed, flagged: totalFlagged };
});

// ─── F1/T5 Extended Card Batch Detection ───────────────────────────────────
// Runs daily. Detects two destabilization archetypes from registry + followup data:
//   T5 (Chronic Borderline) — Yellow tier 12+ consecutive weeks with 1+ completed follow-up cycle
//   F1 (Intervention Failure) — completed follow-up with declining/escalated outcome on open registry item
// Creates new registry items with appropriate extended_card assignment.

registerJobHandler('F1_T5', async (tenantId, scheduledJobId, db) => {
  let totalAnalyzed = 0;
  let totalProcessed = 0;
  let totalFlagged = 0;

  const todayBillEpoch = dateToMoleculeInt(new Date());
  const twelveWeeksAgo = todayBillEpoch - 84; // 12 weeks = 84 days

  // ── T5: Chronic Borderline Management ──
  // Find open YELLOW registry items created 12+ weeks ago that have at least one completed follow-up
  // and do NOT already have a T5 extended card on any open item for the same member
  try {
    const t5Candidates = await db.query(`
      SELECT sr.link, sr.member_link, sr.created_date, sr.protocol_card,
             m.fname, m.lname, m.membership_number
      FROM stability_registry sr
      JOIN member m ON m.link = sr.member_link
      WHERE sr.tenant_id = $1
        AND sr.status = 'O'
        AND sr.urgency = 'YELLOW'
        AND sr.created_date <= $2
        AND EXISTS (
          SELECT 1 FROM registry_followup rf
          WHERE rf.registry_link = sr.link AND rf.completed_ts IS NOT NULL
        )
        AND NOT EXISTS (
          SELECT 1 FROM stability_registry t5
          WHERE t5.member_link = sr.member_link
            AND t5.tenant_id = $1
            AND t5.extended_card = 'T5'
            AND t5.status = 'O'
        )
    `, [tenantId, twelveWeeksAgo]);

    totalAnalyzed += t5Candidates.rows.length;

    // Deduplicate by member_link — one T5 per member per run
    const t5ProcessedMembers = new Set();
    for (const row of t5Candidates.rows) {
      if (t5ProcessedMembers.has(row.member_link)) continue;
      t5ProcessedMembers.add(row.member_link);
      try {
        const activityDate = formatDateLocal(new Date());
        await externalActionHandlers.createRegistryItem({
          memberLink: row.member_link,
          tenantId,
          activityDate,
          actionCode: 'SR_YELLOW', // T5 stays Yellow — transitions to sustained monitoring
          resultDescription: `T5 Chronic Borderline — Yellow tier 12+ weeks (source registry #${row.link})`,
          activityData: {
            EXTENDED_CARD: 'T5',
            PROTOCOL_CARD: 'T5',
            DOMINANT_DRIVER: 'COMPOSITE'
          }
        });
        totalFlagged++;
        debugLog(() => `  🔶 T5 created for member ${row.member_link} (source registry #${row.link}, Yellow since ${row.created_date})`);

        await fireNotificationEvent('EXTENDED_CARD_DETECTED', tenantId, {
          memberLink: row.member_link,
          memberName: `${row.fname} ${row.lname}`,
          detail: 'T5 Chronic Borderline — Yellow tier for 12+ consecutive weeks despite intervention',
          sourcePage: 'physician_detail.html',
          sourceLink: row.membership_number
        });
      } catch (e) {
        console.error(`F1_T5: T5 creation failed for member ${row.member_link}:`, e.message);
      }
      totalProcessed++;
    }
  } catch (e) {
    console.error('F1_T5: T5 detection query failed:', e.message);
  }

  // ── F1: Intervention Failure — Structured Reassessment ──
  // Find completed follow-ups with outcome 'declining' or 'escalated' where:
  //   - The parent registry item is still open
  //   - No F1 extended card already exists for the same member (open)
  try {
    const f1Candidates = await db.query(`
      SELECT DISTINCT sr.link, sr.member_link, sr.urgency, sr.protocol_card,
             rf.followup_id, rf.outcome, rf.completed_ts,
             m.fname, m.lname, m.membership_number
      FROM registry_followup rf
      JOIN stability_registry sr ON sr.link = rf.registry_link
      JOIN member m ON m.link = sr.member_link
      WHERE rf.tenant_id = $1
        AND rf.outcome IN ('declining', 'escalated')
        AND rf.completed_ts IS NOT NULL
        AND sr.status = 'O'
        AND NOT EXISTS (
          SELECT 1 FROM stability_registry f1
          WHERE f1.member_link = sr.member_link
            AND f1.tenant_id = $1
            AND f1.extended_card = 'F1'
            AND f1.status = 'O'
        )
    `, [tenantId]);

    totalAnalyzed += f1Candidates.rows.length;

    // Deduplicate by member_link — one F1 per member per run
    const f1ProcessedMembers = new Set();
    for (const row of f1Candidates.rows) {
      if (f1ProcessedMembers.has(row.member_link)) continue;
      f1ProcessedMembers.add(row.member_link);
      try {
        const activityDate = formatDateLocal(new Date());
        // F1 escalates: if Yellow → Orange, if Orange → Red
        let actionCode = 'SR_ORANGE'; // default escalation
        if (row.urgency === 'ORANGE' || row.urgency === 'RED' || row.urgency === 'SENTINEL') {
          actionCode = 'SR_RED';
        }

        await externalActionHandlers.createRegistryItem({
          memberLink: row.member_link,
          tenantId,
          activityDate,
          actionCode,
          resultDescription: `F1 Intervention Failure — ${row.outcome} outcome at follow-up (source registry #${row.link})`,
          activityData: {
            EXTENDED_CARD: 'F1',
            PROTOCOL_CARD: 'F1',
            DOMINANT_DRIVER: 'COMPOSITE'
          }
        });
        totalFlagged++;
        debugLog(() => `  🔴 F1 created for member ${row.member_link} (${row.outcome} on registry #${row.link})`);

        await fireNotificationEvent('EXTENDED_CARD_DETECTED', tenantId, {
          memberLink: row.member_link,
          memberName: `${row.fname} ${row.lname}`,
          detail: `F1 Intervention Failure — ${row.outcome} outcome at success check`,
          sourcePage: 'physician_detail.html',
          sourceLink: row.membership_number
        });
      } catch (e) {
        console.error(`F1_T5: F1 creation failed for member ${row.member_link}:`, e.message);
      }
      totalProcessed++;
    }
  } catch (e) {
    console.error('F1_T5: F1 detection query failed:', e.message);
  }

  debugLog(() => `📊 F1/T5 batch complete: analyzed=${totalAnalyzed}, processed=${totalProcessed}, flagged=${totalFlagged}`);
  return { analyzed: totalAnalyzed, processed: totalProcessed, flagged: totalFlagged };
});

// ─── NOTIFY_DELIVER — Notification Delivery Processor ─────────────────────
// Runs every 5 minutes. Processes pending deliveries, releases held items
// when delivery window opens, retries failed deliveries.
// Core platform job (tenant_id=0) — processes all tenants.

registerJobHandler('NOTIFY_DELIVER', async (tenantId, scheduledJobId, db) => {
  let totalAnalyzed = 0;
  let totalProcessed = 0;
  let totalFlagged = 0;

  try {
    // 1. Release held items if now inside delivery window
    const heldItems = await db.query(
      `SELECT d.delivery_id, d.tenant_id
       FROM notification_delivery d
       WHERE d.status = 'held'
       ORDER BY d.created_at`
    );

    for (const item of heldItems.rows) {
      const config = await getDeliveryConfig(item.tenant_id, db);
      if (isInsideDeliveryWindow(config)) {
        await db.query(
          `UPDATE notification_delivery SET status = 'pending', held_reason = NULL WHERE delivery_id = $1`,
          [item.delivery_id]
        );
      }
    }

    // 2. Process pending deliveries
    const pending = await db.query(
      `SELECT d.*, pu.display_name
       FROM notification_delivery d
       JOIN platform_user pu ON pu.user_id = d.recipient_user_id
       WHERE d.status = 'pending'
       ORDER BY
         CASE d.severity WHEN 'critical' THEN 0 WHEN 'warning' THEN 1 ELSE 2 END,
         d.created_at
       LIMIT 200`
    );

    totalAnalyzed = pending.rows.length;

    for (const delivery of pending.rows) {
      try {
        const result = await sendDelivery(delivery);
        if (result.success) {
          await db.query(
            `UPDATE notification_delivery SET status = 'sent', sent_at = NOW(), attempt_count = attempt_count + 1, last_attempt_at = NOW() WHERE delivery_id = $1`,
            [delivery.delivery_id]
          );
          totalProcessed++;
        } else {
          // Check retry limit
          const config = await getDeliveryConfig(delivery.tenant_id, db);
          const newAttempts = delivery.attempt_count + 1;
          const newStatus = newAttempts >= config.max_retries ? 'failed' : 'pending';
          await db.query(
            `UPDATE notification_delivery SET status = $1, attempt_count = $2, last_attempt_at = NOW(), error_message = $3 WHERE delivery_id = $4`,
            [newStatus, newAttempts, result.error || 'Send failed', delivery.delivery_id]
          );
          if (newStatus === 'failed') totalFlagged++;
        }
      } catch (e) {
        const config = await getDeliveryConfig(delivery.tenant_id, db);
        const newAttempts = delivery.attempt_count + 1;
        const newStatus = newAttempts >= config.max_retries ? 'failed' : 'pending';
        await db.query(
          `UPDATE notification_delivery SET status = $1, attempt_count = $2, last_attempt_at = NOW(), error_message = $3 WHERE delivery_id = $4`,
          [newStatus, newAttempts, e.message, delivery.delivery_id]
        );
        if (newStatus === 'failed') totalFlagged++;
      }
    }
  } catch (e) {
    console.error('NOTIFY_DELIVER error:', e.message);
  }

  debugLog(() => `📨 NOTIFY_DELIVER complete: analyzed=${totalAnalyzed}, processed=${totalProcessed}, failed=${totalFlagged}`);
  return { analyzed: totalAnalyzed, processed: totalProcessed, flagged: totalFlagged };
});

// ─── NOTIFY_DIGEST — Daily Notification Digest ────────────────────────────
// Runs daily. Bundles warning/info deliveries from last 24 hours into
// a single digest per recipient per channel. Core platform job.

registerJobHandler('NOTIFY_DIGEST', async (tenantId, scheduledJobId, db) => {
  let totalAnalyzed = 0;
  let totalProcessed = 0;
  let totalFlagged = 0;

  try {
    // Find sent warning/info deliveries from last 24 hours that aren't already digested
    // Group by recipient + channel
    const digestCandidates = await db.query(`
      SELECT d.recipient_user_id, d.channel, d.tenant_id,
             COUNT(*) as item_count,
             array_agg(d.delivery_id ORDER BY d.created_at) as delivery_ids,
             string_agg(d.title, ' | ' ORDER BY d.created_at) as titles
      FROM notification_delivery d
      WHERE d.status = 'sent'
        AND d.severity IN ('warning', 'info')
        AND d.digest_batch_id IS NULL
        AND d.sent_at >= NOW() - INTERVAL '24 hours'
      GROUP BY d.recipient_user_id, d.channel, d.tenant_id
      HAVING COUNT(*) >= 2
    `);

    totalAnalyzed = digestCandidates.rows.length;

    for (const group of digestCandidates.rows) {
      try {
        // Create a digest delivery record
        const digestResult = await db.query(
          `INSERT INTO notification_delivery (notification_id, tenant_id, recipient_user_id, channel, status, severity, title, body, created_at)
           VALUES (NULL, $1, $2, $3, 'pending', 'info', $4, $5, NOW())
           RETURNING delivery_id`,
          [group.tenant_id, group.recipient_user_id, group.channel,
           `Daily Digest (${group.item_count} notifications)`,
           `Summary: ${group.titles}`]
        );

        const digestId = digestResult.rows[0].delivery_id;

        // Mark original deliveries as digested
        await db.query(
          `UPDATE notification_delivery SET digest_batch_id = $1 WHERE delivery_id = ANY($2)`,
          [digestId, group.delivery_ids]
        );

        // Send the digest
        const result = await sendDelivery({
          delivery_id: digestId,
          channel: group.channel,
          recipient_user_id: group.recipient_user_id,
          severity: 'info',
          title: `Daily Digest (${group.item_count} notifications)`,
          body: `Summary: ${group.titles}`,
          tenant_id: group.tenant_id
        });

        if (result.success) {
          await db.query(
            `UPDATE notification_delivery SET status = 'sent', sent_at = NOW(), attempt_count = 1, last_attempt_at = NOW() WHERE delivery_id = $1`,
            [digestId]
          );
          totalProcessed++;
        }
      } catch (e) {
        console.error(`NOTIFY_DIGEST: Failed for recipient ${group.recipient_user_id} / ${group.channel}:`, e.message);
        totalFlagged++;
      }
    }
  } catch (e) {
    console.error('NOTIFY_DIGEST error:', e.message);
  }

  debugLog(() => `📬 NOTIFY_DIGEST complete: groups=${totalAnalyzed}, digests_sent=${totalProcessed}, failed=${totalFlagged}`);
  return { analyzed: totalAnalyzed, processed: totalProcessed, flagged: totalFlagged };
});

// --- MEDS API: check single member (called on page load) ---
app.post('/v1/meds/check/:memberLink', async (req, res) => {
  const memberLink = req.params.memberLink;
  const tenantId = parseInt(req.query.tenant_id);
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    // Check if member is due
    const memberResult = await dbClient.query(
      'SELECT meds_next_due FROM member WHERE link = $1 AND tenant_id = $2',
      [memberLink, tenantId]
    );
    if (!memberResult.rows.length) return res.status(404).json({ error: 'Member not found' });

    const todayBillEpoch = dateToMoleculeInt(new Date());
    const medsDate = memberResult.rows[0].meds_next_due;

    if (medsDate > todayBillEpoch) {
      return res.json({ checked: true, due: false, meds_next_due: medsDate });
    }

    // Due — process
    const result = await processMedsForMember(memberLink, tenantId);
    return res.json({ checked: true, due: true, ...result });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// GET /v1/meds/member/:memberLink — full MEDS status for a single member (all cadenced items)
app.get('/v1/meds/member/:memberLink', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const memberLink = req.params.memberLink;
  const tenantId = parseInt(req.query.tenant_id);
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const now = new Date();
    const items = [];

    // Surveys with cadence
    const surveys = await dbClient.query(
      `SELECT s.survey_code, s.survey_name, s.cadence_days,
              (SELECT MAX(ms.end_ts) FROM member_survey ms WHERE ms.member_link = $1 AND ms.survey_link = s.link AND ms.end_ts IS NOT NULL) as last_completed_ts
       FROM survey s WHERE s.tenant_id = $2 AND s.status = 'A' AND s.cadence_days IS NOT NULL AND s.cadence_days > 0`,
      [memberLink, tenantId]
    );
    for (const s of surveys.rows) {
      const item = { type: 'survey', code: s.survey_code, name: s.survey_name, cadence_days: s.cadence_days };
      if (!s.last_completed_ts) {
        item.status = 'never_completed';
        item.last_completed = null;
        item.next_due = null;
        item.days_overdue = null;
      } else {
        const lastDate = new Date(s.last_completed_ts * 1000);
        const nextDue = new Date(lastDate);
        nextDue.setDate(nextDue.getDate() + s.cadence_days);
        item.last_completed = lastDate.toISOString();
        item.next_due = nextDue.toISOString();
        const diffDays = Math.floor((now - nextDue) / (1000 * 60 * 60 * 24));
        if (diffDays > 0) {
          item.status = 'overdue';
          item.days_overdue = diffDays;
        } else if (diffDays > -3) {
          item.status = 'due_soon';
          item.days_until_due = Math.abs(diffDays);
        } else {
          item.status = 'current';
          item.days_until_due = Math.abs(diffDays);
        }
      }
      items.push(item);
    }

    // Compliance items with cadence
    const compliance = await dbClient.query(
      `SELECT mc.member_compliance_id, ci.item_code, ci.item_name, mc.cadence_days,
              (SELECT MAX(cr.result_date) FROM compliance_result cr WHERE cr.member_compliance_id = mc.member_compliance_id) as last_result_date
       FROM member_compliance mc
       JOIN compliance_item ci ON ci.compliance_item_id = mc.compliance_item_id
       WHERE mc.member_link = $1 AND mc.tenant_id = $2 AND mc.status = 'active' AND mc.cadence_days IS NOT NULL AND mc.cadence_days > 0`,
      [memberLink, tenantId]
    );
    for (const c of compliance.rows) {
      const item = { type: 'compliance', code: c.item_code, name: c.item_name, cadence_days: c.cadence_days };
      if (!c.last_result_date) {
        item.status = 'never_completed';
        item.last_completed = null;
        item.next_due = null;
        item.days_overdue = null;
      } else {
        const lastDate = moleculeIntToDate(c.last_result_date);
        const nextDue = new Date(lastDate);
        nextDue.setDate(nextDue.getDate() + c.cadence_days);
        item.last_completed = lastDate.toISOString();
        item.next_due = nextDue.toISOString();
        const diffDays = Math.floor((now - nextDue) / (1000 * 60 * 60 * 24));
        if (diffDays > 0) {
          item.status = 'overdue';
          item.days_overdue = diffDays;
        } else if (diffDays > -3) {
          item.status = 'due_soon';
          item.days_until_due = Math.abs(diffDays);
        } else {
          item.status = 'current';
          item.days_until_due = Math.abs(diffDays);
        }
      }
      items.push(item);
    }

    // Sort: overdue first, then due_soon, then never_completed, then current
    const order = { overdue: 0, due_soon: 1, never_completed: 2, current: 3 };
    items.sort((a, b) => (order[a.status] ?? 9) - (order[b.status] ?? 9));

    res.json({ member_link: memberLink, items });
  } catch (e) {
    console.error(`MEDS member status error for ${memberLink}:`, e.message);
    res.status(500).json({ error: e.message });
  }
});

// POST /v1/meds/seed — calculate meds_next_due for all members in a tenant (one-time init)
app.post('/v1/meds/seed', async (req, res) => {
  const tenantId = parseInt(req.query.tenant_id);
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const members = await dbClient.query(
      'SELECT link FROM member WHERE tenant_id = $1 AND is_active = TRUE',
      [tenantId]
    );

    // FILTER_MEMBER_LIST custauth hook
    const custauth = await getCustauth(tenantId);
    const filtered = await custauth('FILTER_MEMBER_LIST', members.rows, { tenantId, db: dbClient });

    let seeded = 0;
    for (const row of filtered) {
      await calculateMedsNextDue(row.link, tenantId);
      seeded++;
    }

    res.json({ seeded, tenant_id: tenantId });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// GET /v1/meds/summary — dashboard summary of overdue members
app.get('/v1/meds/summary', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const tenantId = parseInt(req.query.tenant_id);
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const todayBillEpoch = dateToMoleculeInt(new Date());

    // Get all overdue members (meds_next_due <= today)
    const result = await dbClient.query(
      `SELECT m.link, m.fname, m.lname, m.membership_number, m.meds_next_due
       FROM member m
       WHERE m.tenant_id = $1 AND m.is_active = TRUE AND m.meds_next_due <= $2
       ORDER BY m.meds_next_due ASC`,
      [tenantId, todayBillEpoch]
    );

    // For each overdue member, find what's overdue
    const overdueMembers = [];
    for (const m of result.rows) {
      const items = [];

      // Check surveys
      const surveys = await dbClient.query(
        `SELECT s.survey_code, s.survey_name, s.cadence_days,
                (SELECT MAX(ms.end_ts) FROM member_survey ms WHERE ms.member_link = $1 AND ms.survey_link = s.link AND ms.end_ts IS NOT NULL) as last_completed_ts
         FROM survey s WHERE s.tenant_id = $2 AND s.status = 'A' AND s.cadence_days IS NOT NULL AND s.cadence_days > 0`,
        [m.link, tenantId]
      );
      for (const s of surveys.rows) {
        if (!s.last_completed_ts) {
          items.push({ type: 'survey', code: s.survey_code, name: s.survey_name, status: 'never_completed' });
        } else {
          const lastDate = new Date(s.last_completed_ts * 1000);
          const nextDue = new Date(lastDate);
          nextDue.setDate(nextDue.getDate() + s.cadence_days);
          if (nextDue <= new Date()) {
            const daysOverdue = Math.floor((new Date() - nextDue) / (1000 * 60 * 60 * 24));
            items.push({ type: 'survey', code: s.survey_code, name: s.survey_name, days_overdue: daysOverdue });
          }
        }
      }

      // Check compliance items
      const compliance = await dbClient.query(
        `SELECT mc.member_compliance_id, ci.item_code, ci.item_name, mc.cadence_days,
                (SELECT MAX(cr.result_date) FROM compliance_result cr WHERE cr.member_compliance_id = mc.member_compliance_id) as last_result_date
         FROM member_compliance mc
         JOIN compliance_item ci ON ci.compliance_item_id = mc.compliance_item_id
         WHERE mc.member_link = $1 AND mc.tenant_id = $2 AND mc.status = 'active' AND mc.cadence_days IS NOT NULL AND mc.cadence_days > 0`,
        [m.link, tenantId]
      );
      for (const c of compliance.rows) {
        if (!c.last_result_date) {
          items.push({ type: 'compliance', code: c.item_code, name: c.item_name, status: 'never_completed' });
        } else {
          const lastDate = moleculeIntToDate(c.last_result_date);
          const nextDue = new Date(lastDate);
          nextDue.setDate(nextDue.getDate() + c.cadence_days);
          if (nextDue <= new Date()) {
            const daysOverdue = Math.floor((new Date() - nextDue) / (1000 * 60 * 60 * 24));
            items.push({ type: 'compliance', code: c.item_code, name: c.item_name, days_overdue: daysOverdue });
          }
        }
      }

      if (items.length > 0) {
        overdueMembers.push({
          link: m.link,
          name: `${m.fname} ${m.lname}`.trim(),
          membership_number: m.membership_number,
          overdue_items: items,
          overdue_count: items.length
        });
      }
    }

    res.json({
      total_overdue_members: overdueMembers.length,
      total_overdue_items: overdueMembers.reduce((sum, m) => sum + m.overdue_count, 0),
      members: overdueMembers
    });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// ============================================================
// ML PREDICTIVE RISK
// ============================================================

const ML_SERVICE_URL = process.env.ML_SERVICE_URL || 'http://127.0.0.1:5050';
const ML_TIMEOUT_MS = 5000;

/**
 * Gather all feature data for a member to send to the ML service.
 */
async function gatherMemberFeatures(memberLink, tenantId, client) {
  const db = client || dbClient;

  // PPSI score + trend — read from activity-attached molecules (same pattern as roster)
  const surveyLinkInfo = await getMoleculeStorageInfo(tenantId, 'MEMBER_SURVEY_LINK');
  const pointsInfo = await getMoleculeStorageInfo(tenantId, 'MEMBER_POINTS');
  let ppsiCurrent = null, ppsiTrend = 0, ppsiVolatility = 0, totalSurveys = 0;

  if (surveyLinkInfo && pointsInfo) {
    const ppsiScores = await db.query(
      `SELECT COALESCE(d54.n1, 0) AS score
       FROM activity a
       JOIN ${surveyLinkInfo.tableName} d4 ON d4.p_link = a.link AND d4.molecule_id = $1
       LEFT JOIN ${pointsInfo.tableName} d54 ON d54.p_link = a.link AND d54.molecule_id = $2
       WHERE a.p_link = $3 AND a.activity_type = 'A'
       ORDER BY a.activity_date DESC LIMIT 5`,
      [surveyLinkInfo.moleculeId, pointsInfo.moleculeId, memberLink]
    );
    const vals = ppsiScores.rows.map(r => r.score);
    if (vals.length > 0) {
      ppsiCurrent = vals[0];
      if (vals.length >= 2) ppsiTrend = vals[0] - vals[vals.length - 1];
      if (vals.length >= 3) {
        const mean = vals.reduce((a, b) => a + b, 0) / vals.length;
        ppsiVolatility = Math.sqrt(vals.reduce((a, v) => a + (v - mean) ** 2, 0) / vals.length);
      }
    }
  }

  // Survey completion count
  const surveyCount = await db.query(
    `SELECT COUNT(*) as cnt FROM member_survey ms
     JOIN survey s ON ms.survey_link = s.link
     WHERE ms.member_link = $1 AND s.tenant_id = $2 AND ms.end_ts IS NOT NULL`,
    [memberLink, tenantId]
  );
  totalSurveys = parseInt(surveyCount.rows[0].cnt);

  // Compliance rate (all time) and misses in last 30 days
  // A "miss" = assigned compliance item with no result AND started more than cadence_days ago
  const compTotal = await db.query(
    `SELECT COUNT(*) as total,
            COUNT(CASE WHEN cr.link IS NOT NULL THEN 1 END) as completed,
            COUNT(CASE WHEN cr.link IS NULL
              AND mc.start_date + COALESCE(mc.cadence_days, 30) * INTERVAL '1 day' < CURRENT_DATE
              AND mc.start_date >= CURRENT_DATE - INTERVAL '30 days'
              THEN 1 END) as misses_30d
     FROM member_compliance mc
     LEFT JOIN compliance_result cr ON cr.member_compliance_id = mc.member_compliance_id
     WHERE mc.member_link = $1 AND mc.tenant_id = $2`,
    [memberLink, tenantId]
  );
  const compRate = compTotal.rows[0].total > 0
    ? parseInt(compTotal.rows[0].completed) / parseInt(compTotal.rows[0].total)
    : 1.0;

  // MEDS data — per member
  const medsFlags = await db.query(
    `SELECT COUNT(*) as cnt FROM notification n
     WHERE n.tenant_id = $1 AND n.member_link = $2 AND n.title LIKE '%MEDS%'
     AND n.created_at > NOW() - INTERVAL '30 days'`,
    [tenantId, memberLink]
  );
  const consecutiveMisses = await db.query(
    `SELECT COUNT(*) as cnt FROM notification n
     WHERE n.tenant_id = $1 AND n.member_link = $2 AND n.title LIKE '%consecutive%'
     AND n.created_at > NOW() - INTERVAL '30 days'`,
    [tenantId, memberLink]
  );

  // Registry items
  const registry = await db.query(
    `SELECT COUNT(*) as total,
            COUNT(CASE WHEN urgency = 'RED' THEN 1 END) as red_count
     FROM stability_registry
     WHERE member_link = $1 AND tenant_id = $2 AND status = 'O'`,
    [memberLink, tenantId]
  );

  // Days enrolled
  const member = await db.query(
    `SELECT enroll_date FROM member WHERE link = $1`,
    [memberLink]
  );
  const enrollDate = member.rows[0]?.enroll_date;
  const daysEnrolled = enrollDate ? dateToMoleculeInt(new Date()) - enrollDate : 0;

  // Days since last PPSI — null means no data, not "999 days missing"
  let daysSinceLastPpsi = null;
  const lastPpsi = await db.query(
    `SELECT MAX(ms.end_ts) as last_ts FROM member_survey ms
     JOIN survey s ON ms.survey_link = s.link
     WHERE ms.member_link = $1 AND s.tenant_id = $2 AND s.survey_code = 'PPSI' AND ms.end_ts IS NOT NULL`,
    [memberLink, tenantId]
  );
  if (lastPpsi.rows[0]?.last_ts) {
    const lastDate = new Date(lastPpsi.rows[0].last_ts * 1000);
    daysSinceLastPpsi = Math.floor((Date.now() - lastDate.getTime()) / 86400000);
  }

  // Days since last Pulse — null means no data
  let daysSinceLastPulse = null;
  const lastPulse = await db.query(
    `SELECT MAX(ms.end_ts) as last_ts FROM member_survey ms
     JOIN survey s ON ms.survey_link = s.link
     WHERE ms.member_link = $1 AND s.tenant_id = $2 AND s.survey_code = 'PROVPULSE' AND ms.end_ts IS NOT NULL`,
    [memberLink, tenantId]
  );
  if (lastPulse.rows[0]?.last_ts) {
    const lastDate = new Date(lastPulse.rows[0].last_ts * 1000);
    daysSinceLastPulse = Math.floor((Date.now() - lastDate.getTime()) / 86400000);
  }

  // Provider Pulse score + trend — activities WITH PULSE_RESPONDENT_LINK
  const pulseInfo = await getMoleculeStorageInfo(tenantId, 'PULSE_RESPONDENT_LINK');
  let pulseCurrent = null, pulseTrend = 0;
  if (pulseInfo && pointsInfo) {
    const pulseScores = await db.query(
      `SELECT COALESCE(d54.n1, 0) AS score
       FROM activity a
       JOIN ${pulseInfo.tableName} d4 ON d4.p_link = a.link AND d4.molecule_id = $1
       LEFT JOIN ${pointsInfo.tableName} d54 ON d54.p_link = a.link AND d54.molecule_id = $2
       WHERE a.p_link = $3 AND a.activity_type = 'A'
       ORDER BY a.activity_date DESC LIMIT 5`,
      [pulseInfo.moleculeId, pointsInfo.moleculeId, memberLink]
    );
    const pVals = pulseScores.rows.map(r => r.score);
    if (pVals.length > 0) {
      pulseCurrent = pVals[0];
      if (pVals.length >= 2) pulseTrend = pVals[0] - pVals[pVals.length - 1];
    }
  }

  return {
    ppsi_current: ppsiCurrent,
    ppsi_trend: ppsiTrend,
    ppsi_volatility: ppsiVolatility,
    pulse_current: pulseCurrent,
    pulse_trend: pulseTrend,
    compliance_rate: compRate,
    compliance_misses_30d: parseInt(compTotal.rows[0].misses_30d),
    survey_completion_rate: totalSurveys > 0 ? 1.0 : 0,
    consecutive_misses: parseInt(consecutiveMisses.rows[0].cnt),
    days_since_last_ppsi: daysSinceLastPpsi,
    days_since_last_pulse: daysSinceLastPulse,
    meds_flags_30d: parseInt(medsFlags.rows[0].cnt),
    registry_open_count: parseInt(registry.rows[0].total),
    registry_red_count: parseInt(registry.rows[0].red_count),
    days_enrolled: daysEnrolled,
    ppii_current: Math.round(calcPPII({ ppsiRaw: ppsiCurrent, pulseRaw: pulseCurrent, compRaw: compRate !== null ? compRate * 100 : null, eventRaw: null }) || ppsiCurrent)
  };
}

/**
 * Call ML service, get prediction, store as molecule if score changed.
 */
async function scoreMemberML(memberLink, tenantId, client, membershipNumber) {
  const db = client || dbClient;

  try {
    // Skip clinicians — only score physicians
    if (await isClinician(memberLink, tenantId)) return null;

    const features = await gatherMemberFeatures(memberLink, tenantId, db);

    // Call ML service with timeout
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), ML_TIMEOUT_MS);

    const resp = await fetch(`${ML_SERVICE_URL}/predict`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...features, membership_number: membershipNumber || 'unknown' }),
      signal: controller.signal
    });
    clearTimeout(timeout);

    if (!resp.ok) return null;
    const prediction = await resp.json();

    // Store score as ML_RISK_SCORE molecule on member (only when changed)
    // 5_data_22: N1 = risk_score, N2 = date (Bill epoch)
    if (prediction.risk_score !== undefined) {
      const existing = await getMoleculeRows(memberLink, 'ML_RISK_SCORE', tenantId);
      const prevScore = existing.length > 0 ? existing[0].n1 : null;
      const today = dateToMoleculeInt(new Date());

      if (prevScore === null || prevScore !== prediction.risk_score) {
        await insertMoleculeRow(memberLink, 'ML_RISK_SCORE', [prediction.risk_score, today], tenantId);
      }
    }

    return prediction;
  } catch (e) {
    if (e.name !== 'AbortError') {
      console.error(`ML scoring error for ${memberLink}:`, e.message);
    }
    return null;
  }
}

// GET /v1/ml/member/:id — get ML prediction for a member
app.get('/v1/ml/member/:id', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const tenantId = req.tenantId;
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const memberRec = await resolveMember(req.params.id, tenantId);
    if (!memberRec) return res.status(404).json({ error: 'Member not found' });

    const prediction = await scoreMemberML(memberRec.link, tenantId, null, req.params.id);
    if (!prediction) return res.json({ available: false, message: 'ML service unavailable' });
    res.json({ available: true, ...prediction });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// GET /v1/ml/report — feature report for all physicians (debug/tuning)
app.get('/v1/ml/report', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const tenantId = req.tenantId;
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const clinicianInfo = await getMoleculeStorageInfo(tenantId, 'IS_CLINICIAN');
    const members = await dbClient.query(
      `SELECT m.membership_number, m.fname, m.lname, m.link
       FROM member m
       WHERE m.tenant_id = $1 AND m.is_active = TRUE
       ${clinicianInfo ? `AND NOT EXISTS (SELECT 1 FROM ${clinicianInfo.tableName} d WHERE d.p_link = m.link AND d.molecule_id = $2 AND d.attaches_to = 'M')` : ''}
       ORDER BY m.membership_number::int`,
      clinicianInfo ? [tenantId, clinicianInfo.moleculeId] : [tenantId]
    );

    const report = [];
    for (const m of members.rows) {
      const features = await gatherMemberFeatures(m.link, tenantId);
      let prediction = null;
      try {
        const controller = new AbortController();
        const timeout = setTimeout(() => controller.abort(), ML_TIMEOUT_MS);
        const resp = await fetch(`${ML_SERVICE_URL}/predict`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ ...features, member_link: m.membership_number }),
          signal: controller.signal
        });
        clearTimeout(timeout);
        if (resp.ok) prediction = await resp.json();
      } catch(e) { console.warn('ML prediction fetch error:', e.message); }
      report.push({
        membership_number: m.membership_number,
        name: `${m.fname} ${m.lname}`,
        features,
        prediction
      });
    }
    res.json({ report, generated: new Date().toISOString() });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// POST /v1/ml/batch — score all active members for a tenant
app.post('/v1/ml/batch', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const tenantId = req.tenantId;
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const members = await dbClient.query(
      `SELECT link FROM member WHERE tenant_id = $1 AND is_active = TRUE`,
      [tenantId]
    );

    // FILTER_MEMBER_LIST custauth hook
    const custauth = await getCustauth(tenantId);
    const filtered = await custauth('FILTER_MEMBER_LIST', members.rows, { tenantId, db: dbClient });

    let scored = 0, errors = 0;
    for (const m of filtered) {
      const result = await scoreMemberML(m.link, tenantId, null, m.membership_number);
      if (result) scored++;
      else errors++;
    }

    res.json({ scored, errors, total_members: members.rows.length });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// GET /v1/ml/member/:id/history — ML score trajectory
app.get('/v1/ml/member/:id/history', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const tenantId = req.tenantId;
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const memberRec = await resolveMember(req.params.id, tenantId);
    if (!memberRec) return res.status(404).json({ error: 'Member not found' });

    const molDef = getCachedMoleculeDef(tenantId, 'ML_RISK_SCORE');
    if (!molDef) return res.json({ history: [] });

    const rows = await getMoleculeRows(memberRec.link, 'ML_RISK_SCORE', tenantId);
    res.json({ history: rows.map(r => ({ risk_score: r.n1, date: r.n2 != null ? moleculeIntToDate(r.n2) : null })) });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// GET /v1/ml/diagnostic — all physicians with features + ML scores (for review/debugging)
app.get('/v1/ml/diagnostic', async (req, res) => {
  if (!dbClient) return res.status(501).json({ error: 'Database not connected' });
  const tenantId = req.tenantId;
  if (!tenantId) return res.status(400).json({ error: 'tenant_id required' });

  try {
    const members = await dbClient.query(
      `SELECT link, fname, lname, membership_number, title FROM member WHERE tenant_id = $1 AND is_active = TRUE ORDER BY lname, fname`,
      [tenantId]
    );

    // Filter out clinicians
    const custauth = await getCustauth(tenantId);
    const physicians = await custauth('FILTER_MEMBER_LIST', members.rows, { tenantId, db: dbClient });

    const report = [];
    for (const m of physicians) {
      const features = await gatherMemberFeatures(m.link, tenantId);

      // Call ML service
      let prediction = null;
      try {
        const controller = new AbortController();
        const timeout = setTimeout(() => controller.abort(), ML_TIMEOUT_MS);
        const resp = await fetch(`${ML_SERVICE_URL}/predict`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(features),
          signal: controller.signal
        });
        clearTimeout(timeout);
        if (resp.ok) prediction = await resp.json();
      } catch (e) { /* ML service down */ }

      report.push({
        name: `${m.title ? m.title + ' ' : ''}${m.fname} ${m.lname}`.trim(),
        membership_number: m.membership_number,
        features,
        prediction: prediction ? {
          risk_score: prediction.risk_score,
          risk_label: prediction.risk_label,
          probability: prediction.probability,
          confidence: prediction.confidence
        } : null
      });
    }

    res.json({ tenant_id: tenantId, physician_count: report.length, physicians: report });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// GET /v1/ml/health — check ML service status
app.get('/v1/ml/health', async (req, res) => {
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 3000);
    const resp = await fetch(`${ML_SERVICE_URL}/health`, { signal: controller.signal });
    clearTimeout(timeout);
    if (resp.ok) {
      const data = await resp.json();
      res.json({ available: true, ...data });
    } else {
      res.json({ available: false });
    }
  } catch (e) {
    res.json({ available: false, error: e.message });
  }
});

